1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PREMIUM = 60;
4	
5	const BASE_PREMIUMS: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	export function claimOffice(request: any): any {
17	  const customer = request.customer;
18	  const results: any[] = [];
19	
20	  for (let stepIndex = 0; stepIndex < request.steps.length; stepIndex++) {
21	    const step = request.steps[stepIndex];
22	
23	    if (step.type === "claim") {
24	      const policyStep = request.steps[step.policy];
25	      const insuranceValues: Record<string, number> = {
26	        sword: 1000,
27	        amulet: 600,
28	        staff: 800,
29	        potion: 400,
30	        rune: 250,
31	        moonstone: 250,
32	      };
33	      let insuranceSum = 0;
34	      for (const item of policyStep.items) {
35	        insuranceSum += insuranceValues[item.type] || 0;
36	      }
37	      const cap = 2 * insuranceSum;
38	      let totalPayout = 0;
39	      for (const damage of step.incident.damages) {
40	        totalPayout += damage.amount - 100;
41	      }
42	      results.push({ payout: totalPayout, remainingCap: cap - totalPayout });
43	      continue;
44	    }
45	
46	    const items = step.items;
47	
48	    const componentCounts: Record<string, number> = {};
49	    for (const item of items) {
50	      if (COMPONENT_TYPES.has(item.type)) {
51	        componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
52	      }
53	    }
54	
55	    let totalPremium = 0;
56	    let policyBasePremium = 0;
57	    const blocksApplied = new Set<string>();
58	
59	    for (const item of items) {
60	      if (!(item.type in BASE_PREMIUMS)) {
61	        throw new Error(`Unknown item type: ${item.type}`);
62	      }
63	      const isBlock = COMPONENT_TYPES.has(item.type) && componentCounts[item.type] === BLOCK_SIZE;
64	      if (isBlock && !blocksApplied.has(item.type)) {
65	        totalPremium += BLOCK_PREMIUM;
66	        policyBasePremium += BASE_PREMIUMS[item.type] * BLOCK_SIZE;
67	        blocksApplied.add(item.type);
68	      } else if (!isBlock) {
69	        let itemPremium = BASE_PREMIUMS[item.type];
70	        policyBasePremium += BASE_PREMIUMS[item.type];
71	        if (item.cursed) {
72	          itemPremium += BASE_PREMIUMS[item.type] * 0.5;
73	        }
74	        if (item.enchantment >= 5) {
75	          itemPremium += BASE_PREMIUMS[item.type] * 0.3;
76	        }
77	        totalPremium += itemPremium;
78	      }
79	    }
80	
81	    if (customer.yearsWithMHPCO >= 2) {
82	      totalPremium -= policyBasePremium * 0.2;
83	    }
84	
85	    totalPremium += policyBasePremium * 0.1;
86	
87	    if (stepIndex > 0) {
88	      totalPremium -= policyBasePremium * 0.15;
89	    }
90	
91	    results.push({ premium: Math.ceil(totalPremium + PROCESSING_FEE) });
92	  }
93	
94	  return results;
95	}
